 document.querySelectorAll('[data-listen-clue]').forEach(b=>b.onclick=()=>{session.learn.listenClues=session.learn.listenClues||[];if(!session.learn.listenClues.includes(b.dataset.listenClue))session.learn.listenClues.push(b.dataset.listenClue);b.classList.add('correct');b.querySelector('span').textContent='听到了！';$('#listenFeedback').textContent=`已找到 ${session.learn.listenClues.length}/${Math.min(4,p.imagery.length)} 个景物。`;persistLearn()});
