 document.querySelectorAll('[data-note-tab]').forEach(button=>button.onclick=()=>{document.querySelectorAll('[data-note-tab]').forEach(x=>x.classList.toggle('active',x===button));document.querySelectorAll('[data-note-panel]').forEach(panel=>panel.hidden=panel.dataset.notePanel!==button.dataset.noteTab)});
 document.querySelectorAll('[data-understand]').forEach(b=>b.onclick=()=>{if(!session.learn.understood.includes(b.dataset.understand))session.learn.understood.push(b.dataset.understand);b.classList.add('selected');b.querySelector('span').textContent=`${p.lines[+b.dataset.understand]} · ${p.explanations[+b.dataset.understand]}`;$('#understandFeedback').textContent=`已叫醒 ${session.learn.understood.length}/${p.lines.length} 句诗。`;persistLearn()});
 document.querySelectorAll('[data-secret]').forEach(b=>b.onclick=()=>{session.learn.secrets=session.learn.secrets||[];if(!session.learn.secrets.includes(b.dataset.secret))session.learn.secrets.push(b.dataset.secret);b.classList.add('found');b.querySelector('span').textContent=p.lines[+b.dataset.secret];$('#understandFeedback').innerHTML=session.learn.secrets.length===4?`四个秘密都找到了！<b>${p.lines.join('，')}</b>`:`已找到 ${session.learn.secrets.length}/4 个秘密。`;persistLearn()});
 const chooseOrder=b=>{const expected=p.lines[selected.length];if(b.dataset.order!==expected){session.learn.hints++;b.classList.add('gentle');$('#orderFeedback').innerHTML=`这里先放“<b>${esc(expected)}</b>”。把画面接起来再试。`;persistLearn();setTimeout(()=>b.classList.remove('gentle'),650);return}selected.push(b.dataset.order);session.learn.orderSelected=[...selected];b.classList.add('correct');setOrderUI(selected,$('#orderTarget'),'[data-order]');session.learn.orderPassed=selected.length===p.lines.length;$('#orderFeedback').textContent=session.learn.orderPassed?'顺序全对，诗卷修好啦！':`第 ${selected.length} 句到位。`;persistLearn()};
 document.querySelectorAll('[data-order]').forEach(b=>{b.onclick=()=>chooseOrder(b);b.ondragstart=e=>e.dataTransfer.setData('text/plain',b.dataset.order)});if($('#orderTarget')){setOrderUI(selected,$('#orderTarget'),'[data-order]');$('#orderTarget').ondragover=e=>e.preventDefault();$('#orderTarget').ondrop=e=>{e.preventDefault();let b=[...document.querySelectorAll('[data-order]')].find(x=>x.dataset.order===e.dataTransfer.getData('text/plain'));if(b)chooseOrder(b)}}if($('#undoOrder'))$('#undoOrder').onclick=()=>{selected.pop();session.learn.orderSelected=[...selected];session.learn.orderPassed=false;setOrderUI(selected,$('#orderTarget'),'[data-order]');persistLearn()};if($('#resetOrder'))$('#resetOrder').onclick=()=>{selected=[];session.learn.orderSelected=[];session.learn.orderPassed=false;setOrderUI(selected,$('#orderTarget'),'[data-order]');persistLearn()};
 document.querySelectorAll('[data-typo-index]').forEach(b=>b.onclick=()=>{if(b.disabled||session.learn.fillPassed)return;let blank=session.learn.blank,ok=+b.dataset.typoIndex===blank.answerIndex;if(ok){session.learn.fillPassed=true;b.classList.add('correct','repaired');b.setAttribute('aria-label',`找到了，${blank.wrongChar}应改成${blank.correctChar}`);b.innerHTML=`<del>${esc(blank.wrongChar)}</del><ins>${esc(blank.correctChar)}</ins>`;document.querySelectorAll('[data-typo-index]').forEach(x=>x.disabled=true);$('#fillFeedback').innerHTML=`找到了！“<b>${esc(blank.wrongChar)}</b>”让画面意思变了，这里应该是“<b>${esc(blank.correctChar)}</b>”。完整诗句：<b>${esc(blank.line)}</b>`}else{session.learn.hints++;b.disabled=true;b.classList.add('gentle');$('#fillFeedback').textContent='这个字没有被换走。再找找哪个字让画面意思变了。'}persistLearn()});
 document.querySelectorAll('[data-fill]').forEach(b=>b.onclick=()=>{if(b.disabled)return;let blank=session.learn.blank,ok=b.dataset.fill===blank.word;document.querySelectorAll('[data-fill]').forEach(x=>x.classList.remove('correct','gentle'));b.classList.add(ok?'correct':'gentle');if(ok){session.learn.fillPassed=true;document.querySelectorAll('[data-fill]').forEach(x=>x.disabled=true);$('#fillFeedback').innerHTML=`找回来了：<b>${esc(blank.line)}</b>`}else{session.learn.hints++;b.disabled=true;$('#fillFeedback').textContent=blank.interaction==='whole-line'?`这句也在诗里，但不是第 ${blank.lineIndex+1} 幅画面对应的句子。`:blank.interaction==='line-bridge'?'这句没有紧跟在上句后面。把全诗从上句往下接。':'这个字词放进空白处读不通，再试一次。'}persistLearn()});if($('#prevBlank'))$('#prevBlank').onclick=()=>{session.learn.blankIndex=Math.max(0,session.learn.blankIndex-1);session.learn.fillPassed=false;render();scrollTo(0,0)};if($('#hint'))$('#hint').onclick=()=>{session.learn.hints++;$('#fillFeedback').textContent=practiceHint(session.learn.blank)};
