setTimeout(()=>{let main=$('#main');if(document.visibilityState==='visible'&&main){let tip=document.createElement('aside');tip.className='rest-reminder';tip.textContent='眼睛休息一下：看看远处，喝口水，再决定要不要继续。';main.append(tip)}},state.settings.minutes*60000);
if('speechSynthesis'in window)speechSynthesis.addEventListener('voiceschanged',()=>{chineseVoice=null});
if('serviceWorker'in navigator){navigator.serviceWorker.addEventListener('controllerchange',()=>{if(sessionStorage.getItem('sw-notice-v29'))return;sessionStorage.setItem('sw-notice-v29','1');let tip=document.createElement('div'),button=document.createElement('button');tip.className='offline-ready update-ready';tip.append('✓ 新版已准备好 ');button.textContent='刷新使用';button.onclick=()=>location.reload();tip.append(button);document.body.append(tip)});navigator.serviceWorker.register('/sw.js?v=29',{updateViaCache:'none'}).then(async reg=>{reg.update();await navigator.serviceWorker.ready;if(!sessionStorage.getItem('offline-ready-v29')){sessionStorage.setItem('offline-ready-v29','1');let tip=document.createElement('div');tip.className='offline-ready';tip.textContent='✓ 离线诗词冒险已准备好';document.body.append(tip);setTimeout(()=>tip.remove(),2400)}}).catch(()=>{})}
